// Extract key themes from the story for cross-domain search
const input = $input.first().json;
const storyContent = input.body?.story_content || '';
const storyLabels = input.body?.story_labels || [];
const storyId = input.body?.story_id || '';

// Extract topic labels for search
const topics = storyLabels
  .filter(l => l.type === 'ai' || l.type === 'editorial')
  .map(l => l.text)
  .join(', ');

// Build search query from content + topics
const searchQuery = `Cross-domain connections: ${topics}. ${storyContent.substring(0, 500)}`;

return [{ json: { storyId, storyContent, topics, searchQuery, storyLabels } }];

// Filter results to exclude same-topic articles and build LLM prompt
const input = $('Extract Themes').first().json;
const pineconeResult = $input.first().json;

const matches = (pineconeResult.result || pineconeResult.matches || [])
  .filter(m => m.metadata)
  .map(m => ({
    id: m.id,
    title: m.metadata.title || '',
    source: m.metadata.source || '',
    content: (m.metadata.content || '').substring(0, 500),
    topic_tags: m.metadata.topic_tags || [],
    score: m.score || 0
  }))
  // Filter out articles with same topics as the story
  .filter(m => {
    const storyTopics = input.topics.toLowerCase().split(', ');
    const articleTopics = (m.topic_tags || []).map(t => t.toLowerCase());
    const overlap = storyTopics.filter(t => articleTopics.includes(t));
    return overlap.length < storyTopics.length; // Must have DIFFERENT topics
  })
  .slice(0, 5);

if (matches.length === 0) {
  return [{ json: { connections: [] } }];
}

const articlesText = matches.map((a, i) => 
  `Article ${i+1}: "${a.title}" (${a.source})\n${a.content}`
).join('\n\n');

return [{ json: { 
  storyContent: input.storyContent,
  topics: input.topics,
  articlesText,
  matches,
  hasMatches: true
} }];

