// Parse Claude response and return connections
const hasMatches = $('Filter Cross-Domain').first().json.hasMatches;
if (!hasMatches) return [{ json: { connections: [] } }];

try {
  const response = $input.first().json;
  const text = response.content?.[0]?.text || '[]';
  let cleaned = text.trim();
  if (cleaned.startsWith('```')) cleaned = cleaned.split('\n', 2)[1].split('```')[0].trim();
  const connections = JSON.parse(cleaned);
  return [{ json: { connections: Array.isArray(connections) ? connections : [] } }];
} catch (e) {
  return [{ json: { connections: [] } }];
}
